// frontend/src/pages/Dashboard.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import PlaceCard from '../components/PlaceCard';
import Analytics from '../components/Analytics';
import Toast from '../components/Toast';
import ProfileModal from '../components/ProfileModal';
import { getPlaces, getPrediction } from '../services/api';

// ── Park + Zoo added ──────────────────────────────────────
const CATEGORIES = [
  { key: 'all',        label: 'All',         icon: '🗺️' },
  { key: 'mall',       label: 'Malls',       icon: '🛍️' },
  { key: 'cafe',       label: 'Cafes',       icon: '☕' },
  { key: 'gym',        label: 'Gyms',        icon: '💪' },
  { key: 'restaurant', label: 'Restaurants', icon: '🍽️' },
  { key: 'park',       label: 'Parks',       icon: '🌳' },
  { key: 'zoo',        label: 'Zoos',        icon: '🦁' },
];

const TABS = ['Explore', 'Analytics'];

function getDistanceKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dL = ((lat2-lat1)*Math.PI)/180, dO = ((lon2-lon1)*Math.PI)/180;
  const a  = Math.sin(dL/2)**2+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dO/2)**2;
  return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
}
function formatDistance(km) {
  return km < 1 ? `${Math.round(km*1000)} m away` : `${km.toFixed(1)} km away`;
}
async function reverseGeocode(lat, lng) {
  try {
    const res  = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`,{ headers:{'Accept-Language':'en'} });
    const data = await res.json();
    const addr = data.address || {};
    return [addr.suburb||addr.neighbourhood, addr.city||addr.town||addr.village].filter(Boolean).slice(0,2).join(', ') || 'Your Location';
  } catch { return 'Your Location'; }
}

export default function Dashboard() {
  const { user, logout } = useAuth();

  const [places, setPlaces]         = useState([]);
  const [predictions, setPred]      = useState({});
  const [category, setCategory]     = useState('all');
  const [search, setSearch]         = useState('');
  const [toast, setToast]           = useState(null);
  const [userCoords, setUserCoords] = useState(null);
  const [locationName, setLocName]  = useState('');
  const [locLoading, setLocLoading] = useState(false);
  const [loading, setLoading]       = useState(false);
  const [tab, setTab]               = useState('Explore');
  const [lastUpdated, setLastUpd]   = useState(null);
  const [profileOpen, setProfile]   = useState(false);
  const [mode, setMode]             = useState('idle');
  const refreshRef                  = useRef(null);

  const showToast = (msg, type='success') => setToast({ message: msg, type });

  const loadPlaces = useCallback(async (cat, q, coords, silent=false) => {
    if (!silent) setLoading(true);
    try {
      const lat = coords?.lat ?? userCoords?.lat ?? null;
      const lng = coords?.lng ?? userCoords?.lng ?? null;
      let data  = await getPlaces(cat, q, lat, lng);

      if (lat && lng) {
        data = data.map(p => {
          if (p.latitude && p.longitude && !p.distance_km) {
            const km = getDistanceKm(lat, lng, parseFloat(p.latitude), parseFloat(p.longitude));
            return { ...p, distance_km: km, distance_label: formatDistance(km) };
          }
          return p;
        });
        if (!q) data.sort((a,b) => (a.distance_km??99)-(b.distance_km??99));
      }

      setPlaces(data);
      setLastUpd(new Date());
      const predEntries = await Promise.all(
        data.map(p => getPrediction(p.id, p.category||'mall').then(pred => [p.id, pred]))
      );
      setPred(Object.fromEntries(predEntries));
    } catch {
      if (!silent) showToast('Could not load places. Make sure backend is running.', 'error');
    } finally {
      if (!silent) setLoading(false);
    }
  }, [userCoords]);

  useEffect(() => {
    if (mode === 'idle') return;
    refreshRef.current = setInterval(() => loadPlaces(category, search, userCoords, true), 5*60*1000);
    return () => clearInterval(refreshRef.current);
  }, [category, search, userCoords, mode]);

  useEffect(() => {
    if (search.trim().length === 0) {
      if (userCoords) { setMode('nearby'); const t=setTimeout(()=>loadPlaces(category,'',userCoords,false),300); return ()=>clearTimeout(t); }
      setPlaces([]); setMode('idle'); return;
    }
    setMode('search');
    const t = setTimeout(() => loadPlaces(category, search, userCoords, false), 600);
    return () => clearTimeout(t);
  }, [search, category]);

  const detectLocation = () => {
    if (!navigator.geolocation) { showToast('Geolocation not supported.','error'); return; }
    setLocLoading(true); setLocName('Detecting location...');
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserCoords(coords);
        const name = await reverseGeocode(coords.lat, coords.lng);
        setLocName(name); setLocLoading(false); setMode('nearby');
        showToast(`📍 ${name} — Loading nearby places...`);
        loadPlaces(category, '', coords, false);
      },
      () => { setLocName(''); setLocLoading(false); showToast('Location access denied.','error'); },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const handleCategoryChange = (cat) => {
    setCategory(cat);
    if (mode !== 'idle') loadPlaces(cat, search, userCoords, false);
  };

  const s = {
    page:    { minHeight:'100vh', background:'#f4f5f7', fontFamily:"'Inter',sans-serif" },
    nav:     { background:'#fff', borderBottom:'1px solid #eee', padding:'0 24px', height:'64px', display:'flex', alignItems:'center', justifyContent:'space-between', position:'sticky', top:0, zIndex:100 },
    logo:    { fontSize:'20px', fontWeight:'800', color:'#1a1a2e', letterSpacing:'-0.5px' },
    logoG:   { color:'#1D9E75' },
    navTabs: { display:'flex', gap:'4px' },
    navTab:  (a) => ({ padding:'8px 18px', border:'none', background:a?'#e8f8f2':'transparent', color:a?'#0f6e56':'#888', borderRadius:'10px', fontSize:'14px', fontWeight:a?'700':'500', cursor:'pointer' }),
    avatarBtn: { display:'flex', alignItems:'center', gap:'8px', padding:'6px 12px', borderRadius:'40px', border:'1.5px solid #eee', background:'#fff', cursor:'pointer' },
    avatar:  { width:'32px', height:'32px', borderRadius:'50%', background:'linear-gradient(135deg,#1D9E75,#0f6e56)', color:'#fff', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:'700', fontSize:'13px' },
    main:    { maxWidth:'1200px', margin:'0 auto', padding:'24px 20px', width:'100%' },
    topRow:  { display:'flex', gap:'10px', marginBottom:'14px', flexWrap:'wrap' },
    searchWrap: { flex:1, minWidth:'200px', position:'relative' },
    searchBox:  { width:'100%', padding:'13px 18px 13px 46px', boxSizing:'border-box', border:'1.5px solid #e8e8e8', borderRadius:'14px', fontSize:'14px', outline:'none', background:'#fff', boxShadow:'0 2px 8px rgba(0,0,0,0.04)', transition:'border-color .2s' },
    searchIcon: { position:'absolute', left:'15px', top:'50%', transform:'translateY(-50%)', fontSize:'16px', pointerEvents:'none' },
    locBtn:  { padding:'13px 18px', background:userCoords?'#1D9E75':'#1a1a2e', color:'#fff', border:'none', borderRadius:'14px', fontSize:'13px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap', display:'flex', alignItems:'center', gap:'6px' },
    locPill: { display:'inline-flex', alignItems:'center', gap:'6px', background:'#e8f8f2', color:'#0f6e56', padding:'7px 14px', borderRadius:'40px', fontSize:'13px', fontWeight:'600', marginBottom:'14px', border:'1.5px solid #b7ebd0' },
    catRow:  { display:'flex', gap:'8px', marginBottom:'16px', flexWrap:'wrap' },
    catBtn:  (a) => ({ padding:'8px 16px', display:'flex', alignItems:'center', gap:'6px', border:'1.5px solid '+(a?'#1D9E75':'#e8e8e8'), borderRadius:'40px', background:a?'#e8f8f2':'#fff', color:a?'#0f6e56':'#666', fontSize:'13px', fontWeight:a?'700':'500', cursor:'pointer' }),
    grid:    { display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(300px,1fr))', gap:'16px' },
    empty:   { textAlign:'center', padding:'60px 20px', color:'#bbb' },
  };

  const renderEmpty = () => {
    if (mode === 'idle') return (
      <div style={{ background:'linear-gradient(135deg,#f0fdf8,#e8f8f2)', border:'1.5px solid #b7ebd0', borderRadius:'20px', padding:'40px 24px', textAlign:'center' }}>
        <div style={{ fontSize:'48px', marginBottom:'14px' }}>📍</div>
        <div style={{ fontSize:'20px', fontWeight:'800', color:'#0f6e56', marginBottom:'8px' }}>Discover Places Around You</div>
        <div style={{ fontSize:'14px', color:'#888', marginBottom:'24px', lineHeight:1.6 }}>
          Detect your location to see nearby malls, cafes, gyms, restaurants, parks & zoos with crowd predictions.
          <br />Or search any place by name.
        </div>
        <button onClick={detectLocation} style={{ padding:'14px 28px', background:'#1D9E75', color:'#fff', border:'none', borderRadius:'14px', fontSize:'15px', fontWeight:'700', cursor:'pointer' }}>
          📍 Detect My Location
        </button>
        <div style={{ marginTop:'24px' }}>
          <div style={{ fontSize:'12px', color:'#bbb', marginBottom:'10px', textTransform:'uppercase', letterSpacing:'0.5px' }}>Or search for</div>
          <div style={{ display:'flex', gap:'8px', justifyContent:'center', flexWrap:'wrap' }}>
            {['DLF Mall','Starbucks','Anytime Fitness','Lodhi Garden','Delhi Zoo','Domino\'s'].map(s => (
              <button key={s} onClick={() => setSearch(s)} style={{ padding:'7px 14px', background:'#fff', border:'1.5px solid #ddd', borderRadius:'20px', fontSize:'13px', color:'#555', cursor:'pointer' }}>{s}</button>
            ))}
          </div>
        </div>
      </div>
    );
    if (loading) return (
      <div style={s.empty}>
        <div style={{ fontSize:'36px', marginBottom:'12px' }}>⏳</div>
        <div style={{ fontWeight:'600', color:'#888' }}>{mode==='nearby' ? 'Finding nearby places...' : `Searching for "${search}"...`}</div>
      </div>
    );
    return (
      <div style={s.empty}>
        <div style={{ fontSize:'48px', marginBottom:'16px' }}>😕</div>
        <div style={{ fontWeight:'700', fontSize:'16px', color:'#888' }}>{mode==='search' ? `No results for "${search}"` : 'No nearby places found'}</div>
        <div style={{ fontSize:'13px', marginTop:'6px', color:'#bbb' }}>Try a different name or spelling</div>
      </div>
    );
  };

  return (
    <div style={s.page}>
      <nav style={s.nav}>
        <div style={s.logo}>Visit<span style={s.logoG}>Wise</span> AI</div>
        <div style={s.navTabs}>
          {TABS.map(t => <button key={t} style={s.navTab(tab===t)} onClick={()=>setTab(t)}>{t}</button>)}
        </div>
        <button style={s.avatarBtn} onClick={() => setProfile(true)}>
          <div style={s.avatar}>{user?.name?.charAt(0).toUpperCase()}</div>
          <span style={{ fontSize:'14px', fontWeight:'600', color:'#1a1a2e' }}>{user?.name?.split(' ')[0]}</span>
          <span style={{ fontSize:'11px', color:'#bbb' }}>▼</span>
        </button>
      </nav>

      <div style={s.main}>
        {tab === 'Explore' && (
          <>
            <div style={s.topRow}>
              <div style={s.searchWrap}>
                <span style={s.searchIcon}>🔍</span>
                <input
                  style={s.searchBox}
                  placeholder="Search mall, cafe, gym, park, zoo..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  onFocus={e => e.target.style.borderColor='#1D9E75'}
                  onBlur={e  => e.target.style.borderColor='#e8e8e8'}
                />
              </div>
              <button style={s.locBtn} onClick={detectLocation} disabled={locLoading}>
                {locLoading ? <><span>⏳</span> Detecting...</> : userCoords ? <><span>📍</span>{locationName||'Location On'}</> : <><span>📍</span>Near Me</>}
              </button>
            </div>

            {userCoords && locationName && (
              <div style={s.locPill}>
                📍 <strong>{locationName}</strong>
                <span style={{ fontSize:'11px', opacity:0.7, fontWeight:'400' }}> · {mode==='nearby'?'Showing nearby places':'Sorted by distance'}</span>
              </div>
            )}

            {/* Category filter — now includes Parks + Zoos */}
            <div style={s.catRow}>
              {CATEGORIES.map(c => (
                <button key={c.key} style={s.catBtn(category===c.key)} onClick={() => handleCategoryChange(c.key)}>
                  {c.icon} {c.label}
                </button>
              ))}
            </div>

            {!loading && places.length > 0 && (
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'14px', flexWrap:'wrap', gap:'8px' }}>
                <span style={{ fontSize:'13px', color:'#aaa' }}>
                  {places.length} {mode==='nearby'?'nearby places':`results for "${search}"`}
                  {userCoords ? ' · Sorted by distance' : ''}
                  {lastUpdated ? ` · ${lastUpdated.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'})}` : ''}
                </span>
                <button onClick={() => loadPlaces(category,search,userCoords,false)} style={{ padding:'6px 14px', border:'1.5px solid #e8e8e8', background:'#fff', color:'#888', borderRadius:'20px', fontSize:'12px', cursor:'pointer', fontWeight:'600' }}>
                  🔄 Refresh
                </button>
              </div>
            )}

            {loading ? renderEmpty() : places.length > 0 ? (
              <div style={s.grid}>
                {places.map(place => (
                  <PlaceCard key={place.id} place={place} prediction={predictions[place.id]} />
                ))}
              </div>
            ) : renderEmpty()}
          </>
        )}

        {tab === 'Analytics' && <Analytics userCoords={userCoords} />}
      </div>

      {profileOpen && <ProfileModal user={user} onClose={() => setProfile(false)} onLogout={logout} />}
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
}
